FUNCTION ComputeSyndrome(received[], n, h[])
// received[] = received codeword
// h[] = coefficients of parity check polynomial
BEGIN
 k = length(h) - 1 // dimension
 syndrome[] = received[0:k] // initialize with received bits

 // Perform division by h(x) using shift register
 // Equivalent to syndrome computation circuit
 FOR i FROM 0 TO n-1 DO
 // Feedback from highest degree term
 feedback = syndrome[k-1]

 // Shift register contents
 FOR j FROM k-1 DOWNTO 1 DO
 syndrome[j] = syndrome[j-1] XOR (feedback * h[j])
 END FOR

 // Add new bit from received
 syndrome[0] = received[i] XOR (feedback * h[0])
 END FOR

 RETURN syndrome // syndrome polynomial coefficients
END FUNCTION

