FUNCTION BuildGeneratorMatrix(n, k, g_poly)
// g_poly = coefficients of generator polynomial
// degree(g_poly) = n - k
BEGIN
 G = CreateMatrix(k, n)

 // Row 0: g(x) padded with zeros
 FOR i FROM 0 TO (n-k) DO
 G[0][i] = g_poly[i]
 END FOR

 // Subsequent rows: cyclic shifts of previous row
 FOR row FROM 1 TO k-1 DO
 FOR col FROM 0 TO n-1 DO
 // Cyclic shift: take from previous row, wrap around
 src_col = (col - 1 + n) MOD n
 G[row][col] = G[row-1][src_col]
 END FOR
 END FOR

 RETURN G
END FUNCTION

